#include<bits/stdc++.h>
using namespace std;
int mp[1001][1001],c[1001],match[1001],n,m;
bool vis[1001];
void color(int x,int col)
{
    c[x]=col;
    for(int i=1;i<=n;i++)
    {
        if(mp[x][i]&&!c[i])
        {
            color(i,3-col);
        }
    }
}
bool km(int x)
{
    for(int i=1;i<=n;i++)
    {
        if(vis[i]||!mp[x][i])
        {
            continue;
        }
        vis[i]=1;
        if(!match[i]||km(match[i]))
        {
            match[i]=x;
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        x++;
        y++;
        mp[x][y]=mp[y][x]=1;
    }
    for(int i=1;i<=n;i++)
    {
        if(!c[i])
        {
            color(i,1);
        }
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        if(c[i]==1)
        {
            memset(vis,0,sizeof(vis));
            ans+=km(i);
        }
    }
    printf("%d",n-ans);
    return 0;
}
